import{_ as a,c as t,o,ag as r}from"./chunks/framework.ZX5IUNw2.js";const h=JSON.parse('{"title":"📂 MOFA Standalone RAW Feeds","description":"","frontmatter":{},"headers":[],"relativePath":"standalone_apps/standalone_raw_feeds_en.md","filePath":"standalone_apps/standalone_raw_feeds_en.md","lastUpdated":1761226461000}'),s={name:"standalone_apps/standalone_raw_feeds_en.md"};function n(l,e,i,d,c,p){return o(),t("div",null,e[0]||(e[0]=[r('<h1 id="📂-mofa-standalone-raw-feeds" tabindex="-1">📂 MOFA Standalone RAW Feeds <a class="header-anchor" href="#📂-mofa-standalone-raw-feeds" aria-label="Permalink to &quot;📂 MOFA Standalone RAW Feeds&quot;">​</a></h1><p>This directory <code>https://github.com/cocopuff2u/MOFA/tree/main/latest_raw_files</code> contains raw output information related to Microsoft Standalone Applications and Mac/iOS App Store applications. These outputs are generated automatically using scripts, providing MacAdmins with the latest information in various formats. This setup simplifies the process of accessing and managing app-related data provided by Microsoft.</p><h2 id="🛠️-repository-overview" tabindex="-1">🛠️ Repository Overview <a class="header-anchor" href="#🛠️-repository-overview" aria-label="Permalink to &quot;🛠️ Repository Overview&quot;">​</a></h2><ul><li><strong>Scripts Location</strong>: All scripts used to retrieve and process the data are located in the <code>https://github.com/cocopuff2u/MOFA/tree/main/.github/actions</code> directory of the repository. These scripts automate the fetching and formatting of app data from Microsoft-provided feeds. The raw data is automatically updated every 2 hours using a GitHub Action, which is triggered by workflows located in the <code>https://github.com/cocopuff2u/MOFA/tree/main/.github/actions</code> directory.</li><li><strong>Purpose</strong>: The scripts collect app metadata, convert it into multiple formats, and ensure the information remains current.</li></ul><h2 id="📄-file-outputs" tabindex="-1">📄 File Outputs <a class="header-anchor" href="#📄-file-outputs" aria-label="Permalink to &quot;📄 File Outputs&quot;">​</a></h2><p>This directory provides app-related data in four widely-used formats: RSS, XML, JSON, and YAML. Each format contains the same set of files for easy comparison and integration into various workflows. Below is a breakdown of the available files by format:</p><h3 id="📰-rss-feeds" tabindex="-1">📰 RSS Feeds <a class="header-anchor" href="#📰-rss-feeds" aria-label="Permalink to &quot;📰 RSS Feeds&quot;">​</a></h3><p><strong>Description</strong>: RSS feeds provide syndicated update notifications for macOS standalone apps. They are rebuilt every 2 hours and published to the MOFA website, with source feeds available on GitHub.</p><ul><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/tree/main/latest_raw_files/macos_standalone_rss" target="_blank" rel="noreferrer">macOS Standalone All RSS Feeds</a></strong> Contains all the generated RSS feeds that are pushed to the MOFA website.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/office_suite_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Office Suite RSS Feeds</a></strong> Contains the RSS feed for Office Suite. K</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/word_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Word RSS Feeds</a></strong> Contains the RSS feed for Word.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/excel_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Excel RSS Feeds</a></strong> Contains the RSS feed for Excel.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/onenote_rss.xml" target="_blank" rel="noreferrer">macOS Standalone OneNote RSS Feeds</a></strong> Contains the RSS feed for OneNote.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/onenote_rss.xml" target="_blank" rel="noreferrer">macOS Standalone OneNote RSS Feeds</a></strong> Contains the RSS feed for OneNote.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/outlook_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Outlook RSS Feeds</a></strong> Contains the RSS feed for Outlook.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/powerpoint_rss.xml" target="_blank" rel="noreferrer">macOS Standalone PowerPoint RSS Feeds</a></strong> Contains the RSS feed for PowerPoint.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/teams_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Teams RSS Feeds</a></strong> Contains the RSS feed for Teams.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/windows_app_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Windows App RSS Feeds</a></strong> Contains the RSS feed for Windows App.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/company_portal_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Company Portal RSS Feeds</a></strong> Contains the RSS feed for Company Portal.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/defender_for_endpoint_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Defender RSS Feeds</a></strong> Contains the RSS feed for Defender.</p></li><li><p><strong><a href="https://mofa.cocolabs.dev/rss_feeds/mau_rss.xml" target="_blank" rel="noreferrer">macOS Standalone Microsoft AutoUpdater RSS Feeds</a></strong> Contains the RSS feed for Microsoft AutoUpdater.</p></li></ul><h3 id="🧩-xml-files" tabindex="-1">🧩 XML Files <a class="header-anchor" href="#🧩-xml-files" aria-label="Permalink to &quot;🧩 XML Files&quot;">​</a></h3><p><strong>Description</strong>: XML provides structured app data, ideal for systems requiring hierarchical data representation.</p><ul><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_update_history.xml" target="_blank" rel="noreferrer">macOS Standalone Update History</a></strong><br> Contains the update history for standalone macOS apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_latest.xml" target="_blank" rel="noreferrer">macOS Standalone Latest</a></strong><br> Provides the latest details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_preview.xml" target="_blank" rel="noreferrer">macOS Standalone Preview</a></strong><br> Provides the preview details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_beta.xml" target="_blank" rel="noreferrer">macOS Standalone Beta</a></strong><br> Provides the beta details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/mac_standalone_cve_history.xml" target="_blank" rel="noreferrer">macOS Standalone CVE History</a></strong><br> Documents CVE (Common Vulnerabilities and Exposures) history for macOS standalone apps.</p></li></ul><h3 id="🌐-json-files" tabindex="-1">🌐 JSON Files <a class="header-anchor" href="#🌐-json-files" aria-label="Permalink to &quot;🌐 JSON Files&quot;">​</a></h3><p><strong>Description</strong>: JSON offers lightweight and easy-to-parse data, commonly used in modern development environments.</p><ul><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_update_history.json" target="_blank" rel="noreferrer">macOS Standalone Update History</a></strong><br> Contains the update history for standalone macOS apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_latest.json" target="_blank" rel="noreferrer">macOS Standalone Latest</a></strong><br> Provides the latest details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_preview.jsonl" target="_blank" rel="noreferrer">macOS Standalone Preview</a></strong><br> Provides the preview details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_beta.json" target="_blank" rel="noreferrer">macOS Standalone Beta</a></strong><br> Provides the beta details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/mac_standalone_cve_history.json" target="_blank" rel="noreferrer">macOS Standalone CVE History</a></strong><br> Documents CVE history for macOS standalone apps.</p></li></ul><h3 id="✍️-yaml-files" tabindex="-1">✍️ YAML Files <a class="header-anchor" href="#✍️-yaml-files" aria-label="Permalink to &quot;✍️ YAML Files&quot;">​</a></h3><p><strong>Description</strong>: YAML offers a human-readable format, ideal for configurations and manual edits.</p><ul><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_update_history.yaml" target="_blank" rel="noreferrer">macOS Standalone Update History</a></strong><br> Contains the update history for standalone macOS apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_latest.yaml" target="_blank" rel="noreferrer">macOS Standalone Latest</a></strong><br> Provides the latest details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_preview.yaml" target="_blank" rel="noreferrer">macOS Standalone Preview</a></strong><br> Provides the preview details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/macos_standalone_beta.yaml" target="_blank" rel="noreferrer">macOS Standalone Beta</a></strong><br> Provides the beta details about macOS standalone apps.</p></li><li><p><strong><a href="https://github.com/cocopuff2u/MOFA/blob/main/latest_raw_files/mac_standalone_cve_history.yaml" target="_blank" rel="noreferrer">macOS Standalone CVE History</a></strong><br> Documents CVE history for macOS standalone apps.</p></li></ul><h2 id="🌟-why-multiple-formats" tabindex="-1">🌟 Why Multiple Formats? <a class="header-anchor" href="#🌟-why-multiple-formats" aria-label="Permalink to &quot;🌟 Why Multiple Formats?&quot;">​</a></h2><p>The choice to provide XML, JSON, and YAML outputs ensures compatibility with a wide range of tools and systems. By supporting multiple formats, we accommodate diverse user needs:</p><ul><li><strong>XML</strong>: Designed for enterprise applications and legacy systems.</li><li><strong>JSON</strong>: Suitable for modern development environments and APIs.</li><li><strong>YAML</strong>: Ideal for user-friendly configuration and quick manual edits.</li></ul><h2 id="📌-usage-instructions" tabindex="-1">📌 Usage Instructions <a class="header-anchor" href="#📌-usage-instructions" aria-label="Permalink to &quot;📌 Usage Instructions&quot;">​</a></h2><ol><li>Locate the required output file in this directory.</li><li>Refer to the scripts in the <code>https://github.com/cocopuff2u/MOFA/tree/main/.github/actions</code> directory to understand or customize how the data is fetched and formatted.</li><li>Choose the format that best fits your application or integration needs.</li></ol><h2 id="🔗-access-the-latest-raw-files" tabindex="-1">🔗 Access the Latest Raw Files <a class="header-anchor" href="#🔗-access-the-latest-raw-files" aria-label="Permalink to &quot;🔗 Access the Latest Raw Files&quot;">​</a></h2><p>You can access all the latest raw files <a href="https://github.com/cocopuff2u/MOFA/tree/main/latest_raw_files" target="_blank" rel="noreferrer">here</a>.</p>',25)]))}const m=a(s,[["render",n]]);export{h as __pageData,m as default};
